+import express from "express";
+import cors from "cors";
+import { db, refreshSnapshotTimestamp } from "./data.js";
+
+const app = express();
+const PORT = process.env.PORT || 4000;
+
+app.use(cors());
+app.use(express.json());
+
+app.get("/health", (_req, res) => {
+  res.json({ ok: true, service: "finance-mvp-api" });
+});
+
+app.get("/v1/me/snapshot", (_req, res) => {
+  refreshSnapshotTimestamp();
+  res.json(db.snapshot);
+});
+
+app.get("/v1/accounts", (req, res) => {
+  const { type } = req.query;
+  if (!type) return res.json({ items: db.accounts });
+  return res.json({
+    items: db.accounts.filter((account) => account.type === type)
+  });
+});
+
+app.get("/v1/transactions", (req, res) => {
+  const { account_id } = req.query;
+  if (!account_id) return res.json({ items: db.transactions });
+  return res.json({
+    items: db.transactions.filter((tx) => tx.account_id === account_id)
+  });
+});
+
+app.get("/v1/ai/insights", (_req, res) => {
+  res.json({ insights: db.aiInsights });
+});
+
+app.post("/v1/payments/bill-pay-intents", (req, res) => {
+  const { card_account_id, funding_account_id, amount, currency = "USD" } = req.body;
+
+  if (!card_account_id || !funding_account_id || !amount) {
+    return res.status(400).json({
+      error_code: "VALIDATION_ERROR",
+      message: "card_account_id, funding_account_id and amount are required"
+    });
+  }
+
+  const intent = {
+    intent_id: `pi_${Date.now()}`,
+    card_account_id,
+    funding_account_id,
+    amount,
+    currency,
+    status: "PENDING",
+    estimated_settlement_at: new Date(Date.now() + 2 * 24 * 60 * 60 * 1000).toISOString(),
+    created_at: new Date().toISOString()
+  };
+
+  db.paymentIntents.push(intent);
+  return res.status(201).json(intent);
+});
+
+app.get("/v1/payments/bill-pay-intents", (_req, res) => {
+  res.json({ items: db.paymentIntents });
+});
+
+app.get("/v1/payments/bill-pay-intents/:intentId", (req, res) => {
+  const intent = db.paymentIntents.find((entry) => entry.intent_id === req.params.intentId);
+  if (!intent) {
+    return res.status(404).json({
+      error_code: "NOT_FOUND",
+      message: "Payment intent not found"
+    });
+  }
+  return res.json(intent);
+});
+
+app.post("/v1/planning/debt-scenarios", (req, res) => {
+  const { strategy = "AVALANCHE", extra_payment_monthly = 300 } = req.body ?? {};
+
+  const base = {
+    AVALANCHE: { months_to_debt_free: 22, total_interest_paid: 4120 },
+    SNOWBALL: { months_to_debt_free: 25, total_interest_paid: 4580 },
+    HYBRID: { months_to_debt_free: 23, total_interest_paid: 4310 }
+  };
+
+  const result = base[strategy] ?? base.AVALANCHE;
+  const adjustedMonths = Math.max(8, result.months_to_debt_free - Math.floor(extra_payment_monthly / 200));
+  const adjustedInterest = Math.max(1200, result.total_interest_paid - extra_payment_monthly * 2.2);
+
+  return res.json({
+    scenario_id: `debt_${Date.now()}`,
+    strategy,
+    months_to_debt_free: adjustedMonths,
+    total_interest_paid: Number(adjustedInterest.toFixed(2)),
+    assumptions: {
+      extra_payment_monthly
+    }
+  });
+});
+
+app.use((err, _req, res, _next) => {
+  console.error(err);
+  res.status(500).json({
+    error_code: "INTERNAL_ERROR",
+    message: "Unexpected server error"
+  });
+});
+
+app.listen(PORT, () => {
+  console.log(`API running on http://localhost:${PORT}`);
+});
*** End Patch

