export function currency(value) {
  return new Intl.NumberFormat("en-US", {
    style: "currency",
    currency: "USD"
  }).format(value ?? 0);
}

export function formatDate(iso) {
  if (!iso) return "—";
  return new Date(iso).toLocaleString("en-US", {
    month: "short",
    day: "numeric",
    hour: "numeric",
    minute: "2-digit"
  });
}

export function pct(value) {
  return `${(value * 100).toFixed(1)}%`;
}

export default function NetWorthChart({ total, change30d }) {
  const points = "0,80 40,65 80,70 120,45 160,50 200,35 240,28 280,20 320,15 360,8";
  const positive = change30d >= 0;

  return (
    <div className="chart-card">
      <div className="chart-header">
        <h3>Net worth over time</h3>
        <div className="range-chips">
          {["1M", "3M", "1Y", "All"].map((r, i) => (
            <button key={r} type="button" className={`chip ${i === 1 ? "active" : ""}`}>
              {r}
            </button>
          ))}
        </div>
      </div>
      <svg viewBox="0 0 360 90" className="line-chart" aria-hidden>
        <polyline fill="none" stroke="currentColor" strokeWidth="2.5" points={points} />
        <linearGradient id="fill" x1="0" y1="0" x2="0" y2="1">
          <stop offset="0%" stopColor="currentColor" stopOpacity="0.2" />
          <stop offset="100%" stopColor="currentColor" stopOpacity="0" />
        </linearGradient>
        <polygon fill="url(#fill)" points={`${points} 360,90 0,90`} />
      </svg>
      <p className="chart-foot">
        Current {total} · 30d change{" "}
        <span className={positive ? "positive" : "negative"}>
          {positive ? "+" : ""}
          {change30d?.toLocaleString("en-US", { style: "currency", currency: "USD" })}
        </span>
      </p>
    </div>
  );
}

import { useMemo, useState } from "react";
import { currency, formatDate } from "../utils/format";

function StatusBadge({ status }) {
  const map = {
    HEALTHY: { cls: "healthy", label: "Healthy" },
    STALE: { cls: "stale", label: "Stale" },
    ACTION_REQUIRED: { cls: "danger", label: "Action required" }
  };
  const s = map[status] || { cls: "healthy", label: status };
  return (
    <span className={`status-badge ${s.cls}`}>
      <span className="dot" /> {s.label}
    </span>
  );
}

export default function CashPage({ accounts, transactions }) {
  const [filter, setFilter] = useState("ALL");
  const [search, setSearch] = useState("");

  const cashTotal = accounts
    .filter((a) => a.type === "CHECKING" || a.type === "SAVINGS")
    .reduce((s, a) => s + a.balance, 0);

  const needsAttention = accounts.filter((a) => a.status !== "HEALTHY").length;

  const filtered = useMemo(() => {
    return accounts.filter((a) => {
      if (filter !== "ALL" && a.type !== filter) return false;
      const q = search.toLowerCase();
      if (!q) return true;
      return (
        a.name.toLowerCase().includes(q) || a.institution.toLowerCase().includes(q)
      );
    });
  }, [accounts, filter, search]);

  return (
    <>
      <header className="page-header row">
        <div>
          <h1>Cash & accounts</h1>
          <p className="muted">All linked depository and card accounts</p>
        </div>
      </header>

      <div className="summary-row">
        <div className="summary-card">
          <span>Total cash</span>
          <strong>{currency(cashTotal)}</strong>
        </div>
        <div className="summary-card">
          <span>Linked institutions</span>
          <strong>{new Set(accounts.map((a) => a.institution)).size}</strong>
        </div>
        <div className="summary-card">
          <span>Needs attention</span>
          <strong>{needsAttention}</strong>
        </div>
      </div>

      <div className="filter-row">
        <select value={filter} onChange={(e) => setFilter(e.target.value)}>
          <option value="ALL">All types</option>
          <option value="CHECKING">Checking</option>
          <option value="SAVINGS">Savings</option>
          <option value="CREDIT_CARD">Credit card</option>
        </select>
        <input
          placeholder="Search accounts…"
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="card table-card">
        <table className="data-table">
          <thead>
            <tr>
              <th>Institution</th>
              <th>Account</th>
              <th>Type</th>
              <th className="num">Balance</th>
              <th className="num">Available</th>
              <th>Last synced</th>
              <th>Status</th>
            </tr>
          </thead>
          <tbody>
            {filtered.map((a) => (
              <tr key={a.id}>
                <td>{a.institution}</td>
                <td>{a.name}</td>
                <td>{a.type.replace("_", " ")}</td>
                <td className="num">{currency(a.balance)}</td>
                <td className="num">{currency(a.available ?? a.balance)}</td>
                <td>{formatDate(a.lastSynced)}</td>
                <td>
                  <StatusBadge status={a.status} />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="card">
        <h3>Recent activity</h3>
        <ul className="tx-list">
          {transactions.slice(0, 8).map((tx) => (
            <li key={tx.id}>
              <div>
                <strong>{tx.description}</strong>
                <p>{tx.category}</p>
              </div>
              <span className={tx.amount >= 0 ? "positive" : "negative"}>
                {currency(tx.amount)}
              </span>
            </li>
          ))}
        </ul>
      </div>
    </>
  );
}

