}

.data-table th.num,
.data-table td.num {
  text-align: right;
}

.data-table.dense td {
  padding: 0.45rem 0.5rem;
}

.row-warn {
  background: #fffbeb;
}

/* Status */
.status-badge {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  font-size: 0.8rem;
  padding: 0.2rem 0.5rem;
  border-radius: 999px;
  background: #f1f5f9;
}

.status-badge.healthy {
  background: #ecfdf5;
  color: #065f46;
}

.status-badge.stale {
  background: #fffbeb;
  color: #92400e;
}

.status-badge.danger {
  background: #fef2f2;
  color: #991b1b;
}

.dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: #94a3b8;
}

.dot.healthy {
  background: var(--positive);
}

.badge {
  display: inline-block;
  font-size: 0.65rem;
  text-transform: uppercase;
  font-weight: 700;
  border-radius: 999px;
  padding: 0.2rem 0.5rem;
}

.badge.actionable {
  background: #ccfbf1;
  color: #115e59;
}
.badge.warning {
  background: #fef3c7;
  color: #92400e;
}
.badge.informational {
  background: #dbeafe;
  color: #1e40af;
}

/* Lists */
.tx-list,
.simple-list {
  list-style: none;
  margin: 0;
  padding: 0;
}

.tx-list li,
.simple-list li {
  display: flex;
  justify-content: space-between;
  padding: 0.65rem 0;
  border-bottom: 1px solid var(--border);
}

.chip-strip {
  display: flex;
  flex-wrap: wrap;
  gap: 0.5rem;
}

.inst-chip {
  display: inline-flex;
  align-items: center;
  gap: 0.35rem;
  padding: 0.35rem 0.65rem;
  background: var(--bg-app);
  border-radius: 999px;
  font-size: 0.85rem;
}

/* Cash page */
.summary-row {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1rem;
  margin-bottom: 1rem;
}

.summary-row.three {
  grid-template-columns: repeat(3, 1fr);
}

.summary-card {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 1rem;
  box-shadow: var(--shadow);
}

.summary-card span {
  font-size: 0.8rem;
  color: var(--text-muted);
}

.summary-card strong {
  display: block;
  font-size: 1.25rem;
  margin-top: 0.25rem;
}

.filter-row {
  display: flex;
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.filter-row select,
.filter-row input {
  flex: 1;
  padding: 0.55rem;
  border: 1px solid var(--border);
  border-radius: 10px;
  font: inherit;
}

/* Invest */
.invest-top {
  display: grid;
  grid-template-columns: 1.2fr 1fr 1fr;
  gap: 1rem;
  margin-bottom: 1rem;
}

.alloc-legend {
  display: grid;
  gap: 0.35rem;
  font-size: 0.9rem;
}

.swatch {
  display: inline-block;
  width: 10px;
  height: 10px;
  border-radius: 2px;
  margin-right: 0.35rem;
}
.swatch.us {
  background: #0d9488;
}
.swatch.intl {
  background: #3b82f6;
}
.swatch.bond {
  background: #8b5cf6;
}
.swatch.cash {
  background: #94a3b8;
}

.offering-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
  gap: 1rem;
}

.offering-card h3 {
  margin: 0.5rem 0 0.25rem;
}

.risk-pill {
  font-size: 0.7rem;
  font-weight: 700;
  text-transform: uppercase;
  padding: 0.2rem 0.5rem;
  border-radius: 999px;
  background: #fef3c7;
  color: #92400e;
}

.risk-pill.low {
  background: #ecfdf5;
  color: #065f46;
}

/* Plan */
.tab-bar {
  display: flex;
  gap: 0.35rem;
  background: var(--bg-app);
  padding: 0.25rem;
  border-radius: 10px;
}

.tab-bar button {
  border: none;
  background: transparent;
  padding: 0.45rem 0.85rem;
  border-radius: 8px;
  cursor: pointer;
  font: inherit;
}

.tab-bar button.active {
  background: #fff;
  box-shadow: var(--shadow);
  font-weight: 600;
}

.budget-header {
  display: flex;
  align-items: center;
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.budget-header h2 {
  margin: 0;
}

.push-right {
  margin-left: auto;
}

.budget-top {
  display: grid;
  grid-template-columns: 200px 1fr;
  gap: 1rem;
  margin-bottom: 1rem;
}

.pace.on-track {
  color: var(--positive);
}
.pace.behind {
  color: var(--warning);
}

.debt-compare {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 1rem;
}

.debt-card h3 {
  margin-top: 0;
}

.debt-controls {
  display: flex;
  gap: 1rem;
  align-items: flex-end;
  flex-wrap: wrap;
}

.debt-controls label {
  display: grid;
  gap: 0.35rem;
  font-size: 0.85rem;
}

.debt-controls input {
  padding: 0.55rem;
  border: 1px solid var(--border);
  border-radius: 8px;
}

/* Bill pay */
.stepper {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1.5rem;
  flex-wrap: wrap;
}

.step {
  display: flex;
  align-items: center;
  gap: 0.35rem;
  font-size: 0.85rem;
  color: var(--text-muted);
}

.step.active {
  color: var(--accent);
  font-weight: 600;
}

.step.done .step-num {
  background: var(--positive);
  color: #fff;
}

.step-num {
  width: 24px;
  height: 24px;
  border-radius: 50%;
  background: var(--border);
  display: grid;
  place-items: center;
  font-size: 0.75rem;
}

.billpay-layout {
  display: grid;
  grid-template-columns: 1fr 300px;
  gap: 1.5rem;
  align-items: start;
}

.billpay-summary.sticky {
  position: sticky;
  top: 1rem;
}

.summary-amount {
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--accent);
}

.card-picker {
  display: grid;
  gap: 0.75rem;
  margin-bottom: 1rem;
}

.pick-card {
  text-align: left;
  padding: 1rem;
  border: 2px solid var(--border);
  border-radius: var(--radius);
  background: #fff;
  cursor: pointer;
  display: grid;
  gap: 0.25rem;
}

.pick-card.selected {
  border-color: var(--accent);
  background: #f0fdfa;
}

.amount-options {
  display: flex;
  gap: 0.5rem;
  margin-bottom: 1rem;
  flex-wrap: wrap;
}

.amount-chip {
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 0.65rem 1rem;
  background: #fff;
  cursor: pointer;
  display: grid;
  text-align: left;
}

.review-list {
  display: grid;
  grid-template-columns: 120px 1fr;
  gap: 0.5rem;
  margin: 1rem 0;
}

.review-list dt {
  color: var(--text-muted);
  font-size: 0.85rem;
}

.wizard-actions {
  display: flex;
  gap: 0.75rem;
  margin-top: 1rem;
}

.success-panel {
  text-align: center;
  padding: 2rem;
}

/* Learn */
.learn-grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
  gap: 1rem;
}

.level-pill {
  font-size: 0.7rem;
  background: var(--bg-app);
  padding: 0.2rem 0.5rem;
  border-radius: 999px;
}

/* Forms */
.form {
  display: grid;
  gap: 0.85rem;
}

label {
  display: grid;
  gap: 0.35rem;
  font-size: 0.85rem;
}

input,
select {
  padding: 0.55rem;
  border: 1px solid var(--border);
  border-radius: 8px;
  font: inherit;
}

.error {
  background: #fee2e2;
  color: #991b1b;
  border: 1px solid #fca5a5;
  border-radius: 8px;
  padding: 0.65rem;
}

.banner-error {
  margin-bottom: 1rem;
}

.status {
  padding: 2rem;
  text-align: center;
  color: var(--text-muted);
}

/* Responsive */
@media (max-width: 1200px) {
  .content-with-rail {
    grid-template-columns: 1fr;
  }
  .ai-rail {
    display: none;
  }
  .kpi-row {
    grid-template-columns: repeat(2, 1fr);
  }
  .home-grid {
    grid-template-columns: 1fr;
  }
  .debt-compare {
    grid-template-columns: 1fr;
  }
  .billpay-layout {
    grid-template-columns: 1fr;
  }
}

@media (max-width: 900px) {
  .app-shell {
    grid-template-columns: 1fr;
  }
  .sidebar {
    display: none;
  }
  .auth-wrap {
    grid-template-columns: 1fr;
  }
  .invest-top {
    grid-template-columns: 1fr;
  }
  .summary-row {
    grid-template-columns: 1fr;
  }
}

